code = """import pandas as pd, json
# load the query result from storage
records = var_call_X6CZMSTYZXb9W38r7hJ2akKd
df = pd.DataFrame(records)
# Normalize caseid, oldvalue, newvalue by stripping whitespace and leading '#'
for col in ['caseid__c','oldvalue__c','newvalue__c']:
    if col in df.columns:
        df[col] = df[col].fillna('').astype(str).str.strip()
        df[col] = df[col].str.lstrip('#').replace({'None':'', "None":""})
# Define transfer events: oldvalue non-empty (meaning a transfer from oldvalue to newvalue)
transfer_events = df[df['oldvalue__c'] != '']
# Count transfers per agent (agent id = oldvalue__c)
transfer_counts = transfer_events['oldvalue__c'].value_counts().to_dict()
# Count handled cases per agent: distinct caseid__c where newvalue__c == agent
# For each newvalue agent, count unique case ids
handled = df[df['newvalue__c'] != '']
handled_group = handled.groupby('newvalue__c')['caseid__c'].nunique().to_dict()
# Build set of agents who handled >0 cases
agents_handled = {agent for agent,count in handled_group.items() if count>0}
# For these agents, get transfer counts (default 0 if not present)
agent_transfer_for_handled = {agent: transfer_counts.get(agent,0) for agent in agents_handled}
# If no agents handled any cases, return empty
if not agent_transfer_for_handled:
    result = None
else:
    # find min transfer count
    min_val = min(agent_transfer_for_handled.values())
    # find agents with that min
    agents_with_min = [a for a,c in agent_transfer_for_handled.items() if c==min_val]
    # If multiple, sort and pick first to return single Id
    agents_with_min_sorted = sorted(agents_with_min)
    result = agents_with_min_sorted[0]
# Print result in required format
print("__RESULT__:")
print(json.dumps(result))"""

